import React from "react";
import { RESUME_PATH } from "../root.link";

const Navbar = () => {
  return (
    <nav className="space-x-10" id="nav-menu">
      <ul className="flex flex-row space-x-4 md:space-x-10 md:text-xl justify-center md:justify-end font-thin">
        <li>
          <a
            href="/"
            className="py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            Home
          </a>
        </li>
        <li>
          <a
            href="#About"
            className="nav-link about nav-link home py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            About
          </a>
        </li>
        <li>
          <a
            href="#projects"
            className="nav-link projects py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            Projects
          </a>
        </li>
        <li>
          <a
            href="#skills"
            className="nav-link skills py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            Skills
          </a>
        </li>
        <li>
          <a
            href="#contact"
            className="nav-link contact py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            Contact
          </a>
        </li>

        <li>
          <a
            href={RESUME_PATH}
            target="_blank"
            rel="noreferrer"
            className="nav-link resume py-1 px-5 hover:bg-gray focus:bg-gray rounded-lg"
          >
            Resume
          </a>
        </li>
      </ul>
    </nav>
  );
};

export default Navbar;
